const symbol = $input.all()[0].json.body?.symbol || $input.all()[0].json.symbol;
const newsData = $input.item.json;
const news = newsData.news || [];

const headlines = news.slice(0, 8).map((n, i) => `${i+1}. ${n.title} (${new Date(n.providerPublishTime * 1000).toLocaleDateString()})`).join('\n');

return [{
  json: {
    symbol,
    headlines,
    prompt: `You are a financial analyst. Analyze these recent news headlines for ${symbol} and provide:\n1. Overall sentiment: BULLISH, BEARISH, or NEUTRAL\n2. Confidence score (0.0 to 1.0)\n3. 2-sentence summary\n4. Key risk factors\n\nHeadlines:\n${headlines}\n\nRespond in JSON format: { "sentiment": "BULLISH|BEARISH|NEUTRAL", "confidence": 0.0-1.0, "summary": "...", "risks": "..." }`
  }
}];

const groqResponse = $input.item.json;
const symbol = $input.all()[2].json.symbol;

let analysis = {};
try {
  const content = groqResponse.choices?.[0]?.message?.content;
  analysis = JSON.parse(content);
} catch(e) {
  analysis = { sentiment: 'NEUTRAL', confidence: 0.5, summary: 'Analysis unavailable', risks: 'N/A' };
}

return [{
  json: {
    symbol,
    sentiment: analysis.sentiment,
    confidence: analysis.confidence,
    summary: analysis.summary,
    risks: analysis.risks,
    analyzedAt: new Date().toISOString()
  }
}];
